1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const liveSet = new Set<string>(cells.map(cellKey));
13	  const neighborCounts = countNeighbors(cells);
14	
15	  const result: Cell[] = [];
16	  for (const [key, { cell, count }] of neighborCounts) {
17	    if (cellLivesNextGeneration(liveSet.has(key), count)) {
18	      result.push(cell);
19	    }
20	  }
21	  return result;
22	}
23	
24	function countNeighbors(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
25	  const counts = new Map<string, { cell: Cell; count: number }>();
26	  for (const [x, y] of cells) {
27	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
28	      const neighbor: Cell = [x + dx, y + dy];
29	      const key = cellKey(neighbor);
30	      const entry = counts.get(key) ?? { cell: neighbor, count: 0 };
31	      entry.count += 1;
32	      counts.set(key, entry);
33	    }
34	  }
35	  return counts;
36	}
37	
38	function cellLivesNextGeneration(isAlive: boolean, neighborCount: number): boolean {
39	  return neighborCount === 3 || (isAlive && neighborCount === 2);
40	}
41

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty set when given empty set", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with two live neighbors (survival)", () => {
15	    const result = nextGeneration([[-1, 0], [0, 0], [1, 0]]);
16	    expect(result).toContainEqual([0, 0]);
17	  });
18	  it("should keep alive a live cell with three live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("should kill a live cell with more than three live neighbors (overpopulation)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("should bring to life a dead cell with exactly three live neighbors (reproduction)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("should preserve a block still life unchanged", () => {
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
32	    const resultSet = new Set(result.map((c) => c.join(",")));
33	    const expectedSet = new Set(["0,0", "1,0", "0,1", "1,1"]);
34	    expect(resultSet).toEqual(expectedSet);
35	  });
36	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
37	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
38	    const resultSet = new Set(result.map((c) => c.join(",")));
39	    const expectedSet = new Set(["-1,1", "0,1", "1,1"]);
40	    expect(resultSet).toEqual(expectedSet);
41	  });
42	  it("should support negative coordinates", () => {
43	    const result = nextGeneration([[-5, -5], [-4, -5], [-5, -4], [-4, -4]]);
44	    const resultSet = new Set(result.map((c) => c.join(",")));
45	    const expectedSet = new Set(["-5,-5", "-4,-5", "-5,-4", "-4,-4"]);
46	    expect(resultSet).toEqual(expectedSet);
47	  });
48	});
