export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>(cells.map(cellKey));
  const neighborCounts = countNeighbors(cells);

  const result: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
